sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    // implement resource here

	var appScope = request.queryParams.app_scope;

	if (!appScope) {
        response.setStatus(400);
        return { error: "app_scope query parameter is required" };
    }

	if (Array.isArray(appScope)) {
		appScope = appScope[0];
	}

	if (appScope != gs.getCurrentScopeName()) {
		response.setStatus(401);
		return { error: "Authorization failed: invalid app_scope" };
	}

	var scopeGR = new GlideRecord('sys_scope');
	scopeGR.addQuery('scope', appScope); // e.g., 'x_12345_xurrent_imr'
	scopeGR.query();
	if (!scopeGR.next()) {
		response.setStatus(401);
		return { error: "Authorization failed: invalid app_scope" };
	} else {
		appSysId = scopeGR.getUniqueValue();
	}

	response.setStatus(200);
    return {
		result: "Success",
		application_scope_id: appSysId,
    };

})(request, response);
